      "content": "const { randomUUID } = require('node:crypto');
const { sendError } = require('../../lib/errors');
const { getProjectById, getTaskById, updateTaskById, createTask, getCommentsByTaskId, createComment } = require('../store');

const createTask = async ({ name, description }) => {
  const taskId = randomUUID();
  return createTask({ taskId, name, description, status: 'todo' });
};

const getTask = async (taskId) => {
  const task = await getTaskById(taskId);
  if (!task) {
    throw sendError(404, 'NOT_FOUND', 'Task not found');
  }
  return task;
};

const updateTask = async (taskId, { status }) => {
  const task = await getTaskById(taskId);
  if (!task) {
    throw sendError(404, 'NOT_FOUND', 'Task not found');
  }
  return updateTaskById(taskId, { status });
};

const getTasksByStatus = async (status) => {
  if (status !== 'todo' && status !== 'done') {
    throw sendError(400, 'BAD_REQUEST', 'Invalid status');
  }
  return getTasksByStatus(status);
};

module.exports = { createTask, getTask, updateTask, getTasksByStatus };
